import json
from jose import jwt

def decode_and_verify_jwt(token):
    try:
        payload = jwt.get_unverified_claims(token)
        return json.dumps(payload, indent=4)
    except Exception as e:
        print(f"Error decoding and verifying JWT token: {e}")